// <auto-generated>
// Rust port of Logger.core.cs. Provides a small leveled logging facade whose
// enabled level and active writers are driven by configuration, matching the
// .NET `loglevel` / `logwriters` appsettings entries.
//
// Three writers are supported, mirroring the .NET LogConsoleWriter /
// LogFileWriter / LogTableWriter:
//   * console  — timestamped lines to stderr.
//   * file     — appended to a per-program, day-rolling `<program>.log` file.
//   * database — inserted into `core.log` via a pluggable sink.
//
// The database writer cannot live here: `common` is the lowest crate and may
// not depend on `persist`. Instead a higher layer (the `logic` crate, via
// `logic::register_db_log_writer`) registers a sink with `set_db_writer`. The
// Logger never runs that sink on the calling thread: records are queued to a
// single background worker thread, so database logging can never block a
// request or let a database/config error panic and take down the server. A
// thread-local re-entrancy guard stops the worker's own SQL logging from being
// re-enqueued.
// </auto-generated>

use std::fs::{self, OpenOptions};
use std::io::Write;
use std::sync::mpsc::Sender;
use std::sync::{Mutex, OnceLock};

use chrono::Utc;

use crate::config::Config;

#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
pub enum LogLevel {
    Error = 0,
    Warning = 1,
    Info = 2,
    Debug = 3,
}

impl LogLevel {
    fn label(self) -> &'static str {
        match self {
            LogLevel::Error => "ERROR",
            LogLevel::Warning => "WARN",
            LogLevel::Info => "INFO",
            LogLevel::Debug => "DEBUG",
        }
    }

    /// Parse a configured level name. Higher levels include all lower ones
    /// (Debug enables everything; Error only errors). Unknown values yield None.
    pub fn parse(s: &str) -> Option<LogLevel> {
        match s.trim().to_ascii_lowercase().as_str() {
            "error" => Some(LogLevel::Error),
            "warning" | "warn" => Some(LogLevel::Warning),
            "info" => Some(LogLevel::Info),
            "debug" | "all" => Some(LogLevel::Debug),
            _ => None,
        }
    }
}

/// One log line, handed to the database sink so the higher layer can map it onto
/// the `core.log` columns. The Rust facade has no caller file/line/member info,
/// so the sink supplies empty defaults for those `NOT NULL` columns.
#[derive(Debug, Clone)]
pub struct LogRecord {
    pub level: String,
    pub timestamp: String,
    pub principal: String,
    pub program: String,
    pub message: String,
}

/// Which writers are active and at what level, resolved once from config.
struct Settings {
    level: LogLevel,
    console: bool,
    file: bool,
    database: bool,
}

static SETTINGS: OnceLock<Settings> = OnceLock::new();
static LEVEL_OVERRIDE: Mutex<Option<LogLevel>> = Mutex::new(None);
// Sender into the background log-writer thread. Logging never touches the
// database on the calling thread; records are queued and a single dedicated
// worker owns all of the database work.
static DB_SENDER: Mutex<Option<Sender<LogRecord>>> = Mutex::new(None);

thread_local! {
    // Set while running inside the database sink so the sink's own SQL logging
    // does not recurse back into the database writer.
    static IN_DB_SINK: std::cell::Cell<bool> = const { std::cell::Cell::new(false) };
}

fn settings() -> &'static Settings {
    SETTINGS.get_or_init(|| {
        let (level_setting, writers_setting) = Config::log_settings();

        let level = level_setting
            .as_deref()
            .and_then(LogLevel::parse)
            .unwrap_or(LogLevel::Info);

        // No `logwriters` configured → console + file (the historical default).
        let writers = writers_setting.unwrap_or_default().to_ascii_lowercase();
        let (console, file, database) = if writers.trim().is_empty() {
            (true, true, false)
        } else {
            (
                writers.contains("console"),
                writers.contains("file"),
                writers.contains("table")
                    || writers.contains("database")
                    || writers.contains("db"),
            )
        };

        Settings {
            level,
            console,
            file,
            database,
        }
    })
}

fn effective_level() -> LogLevel {
    LEVEL_OVERRIDE
        .lock()
        .unwrap()
        .unwrap_or_else(|| settings().level)
}

pub struct Logger;

impl Logger {
    /// Override the configured level at runtime (e.g. from JUMPSTART_LOG).
    pub fn set_level(level: LogLevel) {
        *LEVEL_OVERRIDE.lock().unwrap() = Some(level);
    }

    /// Register the database log writer. Called by a higher layer that can reach
    /// the `persist` crate (`logic::register_db_log_writer`). The sink is only
    /// invoked when the `database` writer is enabled in configuration.
    pub fn set_db_writer<F>(sink: F)
    where
        F: Fn(&LogRecord) + Send + Sync + 'static,
    {
        // Run the actual database write on a single background thread, fed by a
        // channel. Callers (request handlers, startup, etc.) only enqueue a
        // record, so logging can never block a request or — critically — let a
        // database/config error panic and take the server down. The worker
        // marks its own thread with IN_DB_SINK so the sink's internal logging
        // (e.g. "Executing sql ...") is never re-enqueued, and each record is
        // wrapped in catch_unwind so one failed write can't kill the worker.
        let (tx, rx) = std::sync::mpsc::channel::<LogRecord>();
        std::thread::spawn(move || {
            IN_DB_SINK.with(|f| f.set(true));
            for rec in rx {
                let _ = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| sink(&rec)));
            }
        });
        *DB_SENDER.lock().unwrap() = Some(tx);
    }

    pub fn error(message: impl AsRef<str>) {
        Self::write(LogLevel::Error, message.as_ref());
    }

    pub fn warning(message: impl AsRef<str>) {
        Self::write(LogLevel::Warning, message.as_ref());
    }

    pub fn info(message: impl AsRef<str>) {
        Self::write(LogLevel::Info, message.as_ref());
    }

    pub fn debug(message: impl AsRef<str>) {
        Self::write(LogLevel::Debug, message.as_ref());
    }

    fn write(level: LogLevel, message: &str) {
        if level > effective_level() {
            return;
        }

        let s = settings();

        let rec = LogRecord {
            level: level.label().to_string(),
            timestamp: Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
            principal: user_name(),
            program: program_name(),
            message: message.to_string(),
        };

        let line = format!(
            "{} {} {} {} {}\n",
            rec.timestamp, rec.level, rec.principal, rec.program, rec.message
        );

        if s.console {
            eprint!("{}", line);
        }

        if s.file {
            write_file(&rec.program, &line);
        }

        // Database writer: hand the record to the background worker. Skip if we
        // are already on the worker thread (its own SQL logging must not be
        // re-enqueued). Enqueuing never blocks on the database and never panics.
        if s.database && !IN_DB_SINK.with(|f| f.get()) {
            if let Ok(sender) = DB_SENDER.lock() {
                if let Some(tx) = sender.as_ref() {
                    let _ = tx.send(rec);
                }
            }
        }
    }
}

/// Append a line to `<program>.log`, rolling the file over once per day. If the
/// existing file was last written on an earlier UTC day, it is renamed to
/// `<program>-YYYY-MM-DD.log` before the new line is written.
fn write_file(program: &str, line: &str) {
    let base = format!("{}.log", program);

    if let Ok(meta) = fs::metadata(&base) {
        if let Ok(modified) = meta.modified() {
            let modified: chrono::DateTime<Utc> = modified.into();
            let now = Utc::now();
            if modified.date_naive() < now.date_naive() {
                let rolled = format!("{}-{}.log", program, modified.format("%Y-%m-%d"));
                let _ = fs::rename(&base, &rolled);
            }
        }
    }

    if let Ok(mut file) = OpenOptions::new().create(true).append(true).open(&base) {
        let _ = file.write_all(line.as_bytes());
    }
}

fn user_name() -> String {
    std::env::var("USER")
        .or_else(|_| std::env::var("USERNAME"))
        .unwrap_or_else(|_| "unknown".to_string())
}

fn program_name() -> String {
    std::env::current_exe()
        .ok()
        .and_then(|p| p.file_stem().map(|s| s.to_string_lossy().into_owned()))
        .unwrap_or_else(|| "UnknownProgram".to_string())
}
